// Lookup table for fully-built packs.
const FULL_DATA: Record<string, AdventurePackData> = {
  france:           FRANCE_DATA,
  morocco:          MOROCCO_DATA,
  indonesia:        INDONESIA_DATA,
  thailand:         THAILAND_DATA,
  malaysia:         MALAYSIA_DATA,
  spain:            SPAIN_DATA,
  portugal:         PORTUGAL_DATA,
  japan:            JAPAN_DATA,
  vietnam:          VIETNAM_DATA,
  cambodia:         CAMBODIA_DATA,
  china:            CHINA_DATA,
  india:            INDIA_DATA,
  'sri-lanka':      SRI_LANKA_DATA,
  nepal:            NEPAL_DATA,
  turkey:           TURKEY_DATA,
  egypt:            EGYPT_DATA,
  'united-kingdom': UK_DATA,
  australia:        AUSTRALIA_DATA,
  'new-zealand':    NEW_ZEALAND_DATA,
  canada:           CANADA_DATA,
  usa:              USA_DATA,
}

export function getPackData(slug: string): AdventurePackData | null {
  return FULL_DATA[slug] ?? null
}

export function getPackMeta(slug: string): AdventurePackMeta | null {
  return PACK_META.find(p => p.slug === slug) ?? null
}
